/* TFC AI Boot Camp — installable course service worker (generated by build/build_pwa.py)
 *
 *   - Precaches the TFC AI BtCmp shell so the whole course works offline
 *   - HTML: network-first (fresh when online) -> cache -> offline fallback
 *   - CSS/JS: stale-while-revalidate (fast, self-updating)
 *   - other assets: cache-first
 *   - Scope: /family-captain (narrower than the civic /sw.js scope "/", so this worker
 *     wins for course pages via longest-scope-match; everything else stays civic)
 *
 * Course progress lives in localStorage (usmc_voyage_progress_v1 /
 * usmc_voyage_drills_v1) — the worker never touches it, so a cache wipe or
 * SW_VERSION bump never erases a captain's progress.
 *
 * Bump SW_VERSION when the shell changes so installs refresh on next launch.
 */
const SW_VERSION = 'v4-2026-05-31';
const CORE_CACHE = 'fc-core-family-captain-' + SW_VERSION;
const RUNTIME_CACHE = 'fc-runtime-family-captain-' + SW_VERSION;
const OFFLINE_FALLBACK = '/family-captain-voyage.html';

const CORE_ASSETS = [
  "/family-captain.html",
  "/family-captain-voyage.html",
  "/family-captain-tools.html",
  "/family-captain-sovereign.html",
  "/family-captain-heartbeat.html",
  "/family-captain-week-1.html",
  "/family-captain-week-2.html",
  "/family-captain-week-3.html",
  "/family-captain-week-4.html",
  "/family-captain-week-5.html",
  "/family-captain-week-6.html",
  "/family-captain-week-7.html",
  "/assets/css/main.css",
  "/assets/img/favicon.png",
  "/assets/icons/icon-192.png",
  "/assets/icons/icon-512.png",
  "/assets/icons/apple-touch-icon.png"
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CORE_CACHE).then((cache) =>
      cache.addAll(CORE_ASSETS).catch((err) => {
        // Don't fail install on a single missing asset — log and move on.
        console.warn('[fc-sw] some core assets failed to cache', err);
      })
    )
  );
  self.skipWaiting();
});

self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) =>
      Promise.all(
        keys
          // only retire OUR old caches; never touch the civic worker's caches
          .filter((k) => k.startsWith('fc-core-family-captain-') || k.startsWith('fc-runtime-family-captain-'))
          .filter((k) => !k.endsWith(SW_VERSION))
          .map((k) => caches.delete(k))
      )
    ).then(() => self.clients.claim())
  );
});

self.addEventListener('fetch', (event) => {
  const req = event.request;
  if (req.method !== 'GET') return;
  const url = new URL(req.url);
  if (url.origin !== self.location.origin) return;

  const isHTML =
    req.mode === 'navigate' ||
    (req.headers.get('accept') || '').includes('text/html') ||
    url.pathname.endsWith('.html');

  if (isHTML) {
    event.respondWith(
      fetch(req)
        .then((res) => {
          if (res && res.ok) {
            const clone = res.clone();
            caches.open(RUNTIME_CACHE).then((c) => c.put(req, clone)).catch(() => {});
          }
          return res;
        })
        .catch(() =>
          caches.match(req).then((cached) => cached || caches.match(OFFLINE_FALLBACK))
        )
    );
    return;
  }

  const isStyleOrScript = /\.(css|js)$/i.test(url.pathname);
  if (isStyleOrScript) {
    event.respondWith(
      caches.match(req).then((cached) => {
        const networkFetch = fetch(req).then((res) => {
          if (res && res.ok && res.type === 'basic') {
            const clone = res.clone();
            caches.open(RUNTIME_CACHE).then((c) => c.put(req, clone)).catch(() => {});
          }
          return res;
        }).catch(() => cached);
        return cached || networkFetch;
      })
    );
    return;
  }

  // Other static assets (images, fonts, json): cache-first.
  event.respondWith(
    caches.match(req).then((cached) => {
      if (cached) return cached;
      return fetch(req).then((res) => {
        if (res && res.ok && res.type === 'basic') {
          const clone = res.clone();
          caches.open(RUNTIME_CACHE).then((c) => c.put(req, clone)).catch(() => {});
        }
        return res;
      }).catch(() => cached);
    })
  );
});
